// The FOOD–DRUG interaction dataset, loaded onto the curated-dataset framework (issue
// #860 Track B). Copies the drug-interactions.ts shape: import the envelope JSON
// (generated by scripts/gen-food-drug-interactions.ts), validate it once with
// loadDataset(), and expose the guidance ENTRIES the matcher consumes. Identity is the
// stable slug `key` (fieldStrategy) — one entry per key, so the harness's
// identity-resolves / refusal-gate hold. The registry lists this for the linter;
// lib/food-drug-interactions.ts is the DOMAIN matcher (it resolves an item to entries by
// RxCUI / synonym, a many-to-one lookup that is domain logic, not the entry identity).
// Pure — no DB, no network.

import rawFoodDrug from "./data/food-drug-interactions.json";
import { loadDataset } from "./loader";
import { fieldStrategy } from "./matcher";
import type { FoodDrugEntry } from "@/scripts/gen-food-drug-interactions";

export type {
  FoodDrugEntry,
  Severity,
} from "@/scripts/gen-food-drug-interactions";

// The validated dataset (envelope + guarantees). Throws at module load if the committed
// JSON ever violates the contract — a loud, early failure.
export const foodDrugInteractionsDataset =
  loadDataset<FoodDrugEntry>(rawFoodDrug);

// Identity strategy: the stable slug `key` (case-folded). For the linter/harness — each
// entry carries a unique key, so identity resolves and an unknown key refuses (null).
export const foodDrugKeyStrategy = fieldStrategy("key");

// The guidance rules (entries) the domain matcher consumes, in curated (source) order.
export const FOOD_DRUG_INTERACTIONS: FoodDrugEntry[] =
  foodDrugInteractionsDataset.entries;
